// Add metadata and convert temperature from raw to Celsius
const raw = msg.payload;

// If payload is a string, try to parse it
let data = {};
if (typeof raw === 'string') {
  try { data = JSON.parse(raw); } catch(e) { data = { raw }; }
} else if (typeof raw === 'object' && raw !== null) {
  data = raw;
} else {
  data = { value: raw };
}

// Example transformation: scale raw ADC value to Celsius
if (data.rawAdc !== undefined) {
  data.temperatureCelsius = ((data.rawAdc / 4095) * 330) - 40;
}

// Attach pipeline metadata
data._pipeline = {
  processedAt: new Date().toISOString(),
  agentVersion: '1.0.0',
  deviceId: msg.deviceId || 'unknown'
};

msg.payload = data;
return msg;
